<?php require_once __DIR__ . '/../includes/header.php'; require_once __DIR__ . '/../includes/csrf.php';
if($_SERVER['REQUEST_METHOD']==='POST' && current_user()['role']==='Admin'){csrf_check();if(($_POST['action']??'')==='delete'){$pdo->prepare('DELETE FROM message_templates WHERE id=?')->execute([$_POST['id']]);}else{$pdo->prepare('INSERT INTO message_templates(channel,category,title,body,created_by,created_at) VALUES (?,?,?,?,?,NOW())')->execute([$_POST['channel'],$_POST['category'],$_POST['title'],$_POST['body'],current_user()['id']]);}redirect_to('templates/index.php');}
$templates=$pdo->query('SELECT * FROM message_templates ORDER BY channel,title')->fetchAll();
?><h3>Outreach Templates</h3><?php if(current_user()['role']==='Admin'):?><div class="card card-body mb-3"><form method="post" class="row g-2"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><div class="col-md-2"><select class="form-select" name="channel"><option>WhatsApp</option><option>Email</option><option>Facebook/Instagram DM</option><option>LinkedIn</option></select></div><div class="col-md-2"><input class="form-control" name="category" placeholder="Category"></div><div class="col-md-3"><input class="form-control" name="title" placeholder="Template title" required></div><div class="col-md-5"><button class="btn btn-primary w-100">Save Template</button></div><div class="col-md-12"><textarea class="form-control" name="body" rows="3" placeholder="Message body"></textarea></div></form></div><?php endif; ?>
<div class="row g-3"><?php foreach($templates as $t):?><div class="col-md-6"><div class="card"><div class="card-body"><h6><?= e($t['title']) ?></h6><div class="small text-muted mb-2"><?= e($t['channel']) ?> / <?= e($t['category']) ?></div><pre id="tpl<?= (int)$t['id'] ?>" class="bg-light p-2 rounded" style="white-space: pre-wrap"><?= e($t['body']) ?></pre><button class="btn btn-sm btn-outline-secondary" data-copy-target="tpl<?= (int)$t['id'] ?>">Copy</button><?php if(current_user()['role']==='Admin'):?><form method="post" class="d-inline"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()) ?>"><input type="hidden" name="action" value="delete"><input type="hidden" name="id" value="<?= (int)$t['id'] ?>"><button class="btn btn-sm btn-outline-danger">Delete</button></form><?php endif;?></div></div></div><?php endforeach;?></div>
